scripts.postResponse:
rq.test('Status is 200', function(){ rq.response.to.have.status(200); });
let json = {}; try { json = rq.response.json(); } catch(e) {}
rq.test('Response has array/object payload', function(){
  const isArray = Array.isArray(json);
  const hasList = Array.isArray(json.results) || Array.isArray(json.transactions) || Array.isArray(json.history);
  rq.expect(isArray || hasList || typeof json === 'object').to.eql(true);
});
